  ('social-worker-moex-00941', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務方案的目的主要在協助個人、團體或社區解決問題，一旦問題被確認和界定後，這些問 題必須要先被轉換成什麼，才能再轉換成服務或介入的相關策略？', '["術語", "需求", "資源", "標的人口群"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00942', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在擬訂新的政策或方案時，常常會透過舉辦焦點團體來收集相關需求，這種進行需求評量的作為 是何種需求概念？', '["規範性需求", "感覺性需求", "表達性需求", "比較性需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00943', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '相較於方案「外部評估」，有關「內部評估」（internalevaluation）的敘述，下列何者錯誤？', '["評估結果具有可靠性與客觀性", "較易掌握組織結構與方案的相關內容與知識", "可隨時掌握方案的進度與第一手消息", "較可避免方案執行者的防衛機制"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00944', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '邏輯模式的方案規劃提供一個用以檢驗方案構成要素的架構，包含輸入、過程、輸出、成果與影 響等。下列關於這五個要素的說明，何者正確？', '["針對方案之服務對象進行問題分析與優勢剖析，此是屬於影響要素的工作重點", "過程要素是指使用輸入之資源與原料，以達成方案目標所需實施的各項活動與程序", "輸出是指服務對象在方案開始與結束之間，其生活品質所產生改變的測量", "成果是指方案活動的直接產物，以確認服務對象實際接受的服務量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00945', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於方案「形成性評估」（formativeevaluation）之敘述，下列何者錯誤？', '["焦點在於過程目標", "有助於了解方案執行時的阻力與助力", "有助於方案執行者判斷是否需要修正方案的運作", "用來評估方案的成果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00946', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關人事管理與人力資源管理之間的區別，下列敘述何者錯誤？', '["人事管理是以組織為主，人力資源管理是以成員為主", "人事管理是功能取向，人力資源管理是作業取向", "人事管理的勞資關係保守，人力資源管理有適當的溝通管道", "人事管理的管理模式是反應式，人力資源管理是預警式"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
