  ('social-worker-moex-00948', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '組織分部化主要是建立在「處遇方法專門化」之信念上，期待形成所謂的「專精領域」，係屬於下 列何種部門劃分的類型？', '["依「方案」分部化", "依「功能」分部化", "依「服務」分部化", "依「地區」分部化"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00949', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志工是社會福利機構重要的人力資源，辦理志工表揚是屬於志工管理的那個面向？', '["志工招募", "志工訓練", "志工激勵", "志工維繫"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00950', 'social-worker', 'social-worker-moex-111-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '風險係指潛在影響組織目標之事件，及其發生之可能性與嚴重程度。就組織層次而言，風險管理 可以協助組織改善績效，下列何者不是風險管理執行的要項？', '["風險辨識", "風險分析", "風險評量", "追求零風險"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "256f284a7924", "answer_pdf_sha1": "bd7d5afd3569", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
